// Recommendation engine
function getRecommendations(answers) {
  const goals = answers.goals || [];
  const exp = answers.experience || "none";
  const concerns = answers.concerns || [];
  const hasCancer = concerns.includes("cancer_hx");
  const hasCardiac = concerns.includes("cardiac");
  const hasDiabetes = concerns.includes("diabetes");
  const isPregnant = concerns.includes("pregnant");
  
  if (isPregnant) return { 
    stack: [], 
    message: "Peptide use is not recommended during pregnancy or nursing. Please consult your physician.",
    warning: true 
  };

  let recs = [];
  let reasoning = [];

  // Always include BPC-157 for recovery unless cancer hx
  if (!hasCancer && (goals.includes("recovery") || goals.includes("muscle") || goals.includes("energy"))) {
    recs.push("bpc157");
    reasoning.push("BPC-157 for tissue repair and gut protection");
  }

  // Weight loss stack
  if (goals.includes("weightloss")) {
    if (exp === "none") {
      recs.push("aod9604");
      reasoning.push("AOD-9604 — gentle fat loss entry point for beginners");
    } else {
      recs.push("retatrutide");
      reasoning.push("Retatrutide — most powerful fat loss peptide available");
    }
    recs.push("motsc");
    reasoning.push("MOTS-c — AMPK activation boosts fat metabolism");
    if (!hasCancer) recs.push("ghkcu");
    reasoning.push("GHK-Cu — protects lean mass during weight loss");
  }

  // Cognitive goals
  if (goals.includes("cognitive")) {
    recs.push("semax");
    recs.push("selank");
    reasoning.push("Semax + Selank — the cognitive stack (always pair these)");
    recs.push("ss31");
    reasoning.push("SS-31 — mitochondrial support for sustained mental energy");
  }

  // Longevity
  if (goals.includes("longevity")) {
    recs.push("epithalon");
    reasoning.push("Epithalon — telomere support and circadian regulation");
    recs.push("ss31");
    recs.push("motsc");
    if (!hasCancer) { recs.push("thymosinA1"); reasoning.push("Thymosin Alpha-1 — immune optimization"); }
  }

  // Muscle / body comp
  if (goals.includes("muscle")) {
    if (exp !== "none") {
      recs.push("ipamorelin");
      recs.push("cjc1295");
      reasoning.push("Ipamorelin + CJC-1295 — gold standard GH stack for body comp");
    } else {
      recs.push("sermorelin");
      reasoning.push("Sermorelin — gentlest GH entry point for beginners");
    }
  }

  // Sleep
  if (goals.includes("sleep") || answers.lifestyle === "shiftwork") {
    if (!recs.includes("epithalon")) recs.push("epithalon");
    recs.push("dsip");
    reasoning.push("DSIP + Epithalon — deep sleep and circadian reset (critical for shift workers)");
  }

  // Energy
  if (goals.includes("energy")) {
    if (!recs.includes("ss31")) recs.push("ss31");
    if (!recs.includes("motsc")) recs.push("motsc");
    reasoning.push("SS-31 + MOTS-c — mitochondrial energy stack");
  }

  // Hormones
  if (goals.includes("hormones")) {
    recs.push("kisspeptin10");
    recs.push("gonadorelin");
    reasoning.push("Kisspeptin-10 + Gonadorelin — natural testosterone axis support");
  }

  // Cardiac concern — add SS-31
  if (hasCardiac && !recs.includes("ss31")) {
    recs.push("ss31");
    reasoning.push("SS-31 — added for cardiovascular protection");
  }

  // Dedupe and limit to 6
  const unique = [...new Set(recs)].slice(0, 6);
  return { stack: unique, reasoning, message: null, warning: false };
}

