// QUIZ SCREEN
// ══════════════════════════════════════════════════════════════════════════════
function QuizScreen({ onComplete }) {
  const [step, setStep] = useState(0);
  const [answers, setAnswers] = useState({});
  const q = QUIZ[step];
  const total = QUIZ.length;

  const toggle = (qid, oid, multi) => {
    setAnswers(prev => {
      if (multi) {
        const cur = prev[qid] || [];
        return { ...prev, [qid]: cur.includes(oid) ? cur.filter(x=>x!==oid) : [...cur, oid] };
      }
      return { ...prev, [qid]: oid };
    });
  };

  const selected = (qid, oid) => {
    const a = answers[qid];
    return Array.isArray(a) ? a.includes(oid) : a === oid;
  };

  const canAdvance = answers[q.id] && (Array.isArray(answers[q.id]) ? answers[q.id].length > 0 : true);

  const finish = () => {
    const recs = getRecommendations(answers);
    onComplete(answers, recs);
  };

  return (
    <div style={{ minHeight:"100vh", background:C.bg, display:"flex", flexDirection:"column" }}>
      {/* Header */}
      <div style={{ padding:"20px 20px 0", display:"flex", alignItems:"center", gap:12 }}>
        <LuminosOrb size={28}/>
        <div style={{ flex:1 }}>
          <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6 }}>
            <span style={{ fontSize:12, color:C.muted }}>Step {step+1} of {total}</span>
            <span style={{ fontSize:12, color:C.muted }}>{Math.round(((step)/total)*100)}%</span>
          </div>
          <div style={{ background:C.surface, borderRadius:4, height:4 }}>
            <div style={{ width:`${((step)/total)*100}%`, height:"100%", background:GRAD, borderRadius:4, transition:"width 0.4s" }}/>
          </div>
        </div>
      </div>

      <div style={{ flex:1, padding:"24px 20px", overflowY:"auto" }}>
        <div style={{ fontSize:22, fontWeight:700, marginBottom:6, lineHeight:1.3 }}>{q.question}</div>
        <div style={{ fontSize:13, color:C.muted, marginBottom:22 }}>{q.subtitle}</div>

        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
          {q.options.map(opt => {
            const sel = selected(q.id, opt.id);
            return (
              <div key={opt.id}
                onClick={()=>toggle(q.id, opt.id, q.multi)}
                style={{
                  background: sel ? `${C.violet}33` : C.card,
                  border: `1.5px solid ${sel ? C.violet : C.border}`,
                  borderRadius:14, padding:"14px 12px", cursor:"pointer",
                  transition:"all 0.15s",
                }}>
                <div style={{ fontSize:22, marginBottom:6 }}>{opt.icon}</div>
                <div style={{ fontSize:13, fontWeight:600, color:C.text, marginBottom:3 }}>{opt.label}</div>
                <div style={{ fontSize:11, color:C.muted, lineHeight:1.3 }}>{opt.desc}</div>
                {sel && <div style={{ width:18, height:18, borderRadius:"50%", background:C.violet, display:"flex", alignItems:"center", justifyContent:"center", fontSize:11, color:"#fff", marginTop:8 }}>✓</div>}
              </div>
            );
          })}
        </div>
      </div>

      <div style={{ padding:"0 20px 20px" }}>
        {step > 0 && (
          <button onClick={()=>setStep(s=>s-1)} style={{...S.btn("outline"), marginBottom:10}}>← Back</button>
        )}
        {step < total-1
          ? <button onClick={()=>canAdvance && setStep(s=>s+1)} style={{...S.btn(), opacity:canAdvance?1:0.4}}>Continue →</button>
          : <button onClick={()=>canAdvance && finish()} style={{...S.btn(), opacity:canAdvance?1:0.4}}>See My Recommendations →</button>
        }
        <button onClick={()=>onComplete(null,null)} style={{background:"none",border:"none",color:C.dim,fontSize:12,cursor:"pointer",width:"100%",marginTop:10,textAlign:"center"}}>Skip quiz — explore on my own</button>
      </div>
    </div>
  );
}

