// Stack recommendations based on quiz answers
function buildRecommendedStack(answers) {
  const stacks = {
    fat_loss:   ["retatrutide","motsc","bpc157","ghkcu","ss31"],
    cognitive:  ["semax","selank","ss31","motsc","epithalon"],
    longevity:  ["epithalon","thymalin","ss31","ghkcu","thymosinA1"],
    recovery:   ["bpc157","tb500","ghkcu","thymosinA1","ss31"],
    hormones:   ["ipamorelin","cjc1295","motsc","ghkcu","gonadorelin"],
    sleep:      ["epithalon","dsip","selank","sermorelin","ss31"],
  };
  const primary = answers.goal?.[0] || "recovery";
  let stack = [...(stacks[primary] || stacks.recovery)];

  // Add secondary goals
  const sec = answers.secondary || [];
  if(sec.includes("gut")) stack = [...new Set([...stack, "bpc157","kpv"])];
  if(sec.includes("skin")) stack = [...new Set([...stack, "ghkcu"])];
  if(sec.includes("immune")) stack = [...new Set([...stack, "thymosinA1","ll37"])];
  if(sec.includes("sexual")) stack = [...new Set([...stack, "pt141","kisspeptin10"])];
  if(sec.includes("mood")) stack = [...new Set([...stack, "selank"])];

  // Safety filters
  const concerns = answers.concerns || [];
  if(concerns.includes("cancer_hx")) stack = stack.filter(id => !["bpc157","tb500","ll37"].includes(id));
  if(concerns.includes("diabetes")) stack = stack.filter(id => !["mk677","ghrp6"].includes(id));
  if(concerns.includes("thyroid")) stack = stack.filter(id => !["semaglutide","tirzepatide","retatrutide"].includes(id));

  // Beginner: simplify
  if(answers.experience?.[0] === "beginner") stack = stack.slice(0,3);

  return stack.slice(0,6);
}

